以下是一个重构后的代码，可以处理上面这个问题。

```
QVariantList opt;
QVariantList paras;
paras.append(-1);
QString role;

struct Option {
    QString type;
    QString role;
    QString opt;
};

Option options[] = {
    {"TAG",     "tagVis",       "SET_ANNOTATION_VIS"},
    {"LEGEND",  "legendVis",    "SET_LEGEND_VIS"},
    {"WLPOLICY", "wlPolicy",    "SET_WL_POLICY"},
    {"ROIPOLICY", "roiPolicy",  "SET_ROI_POLICY"},
    {"OPTIMIZED", "optimized",  "SET_OPTIMIZED"},
    {"SAME",    "sameVis",      ""}
};

int index = -1;
for (int i = 0; i < 6; i++) {
    if (STRING_CMP(type, options[i].type)) {
        index = i;
        break;
    }
}

if (index != -1) {
    role = options[index].role;
    opt.append(options[index].opt);
}
```

